// 1. Publisher:
@Service
class CacheInvalidationPublisher {
    private final RedisTemplate<String, String> redis;
    CacheInvalidationPublisher(RedisTemplate<String,String> r) { redis=r; }

    public void publish(String channel, String key) {
        redis.convertAndSend(channel, key);  // PUBLISH channel key
        System.out.println("[Published] " + channel + " → " + key);
    }
}

// 2. Handler (called by adapter on message arrival):
@Component
class CacheInvalidationHandler {
    public void onMessage(String message) {
        System.out.println("[Received] Key to invalidate: " + message);
        // In production: cacheManager.getCache(cacheName).evict(message);
    }
}

// 3. Config wiring them together:
@Configuration
class PubSubConfig {
    @Bean
    public RedisMessageListenerContainer container(
            RedisConnectionFactory factory, MessageListenerAdapter adapter) {
        var c = new RedisMessageListenerContainer();
        c.setConnectionFactory(factory);
        // Subscribe to 'cache.invalidate.*' channels:
        c.addMessageListener(adapter, new PatternTopic("cache.invalidate.*"));
        return c;
    }

    @Bean
    public MessageListenerAdapter adapter(CacheInvalidationHandler h) {
        // Routes: byte[] message → String → h.onMessage(String)
        return new MessageListenerAdapter(h, "onMessage");
    }
}

// HOW THEY CONNECT:
// Publisher: redis.convertAndSend('cache.invalidate.products', 'P001')
// Redis: delivers 'P001' to all subscribers of 'cache.invalidate.products'
// Container: receives the raw bytes
// Adapter: deserializes bytes to String, calls handler.onMessage('P001')
// Handler: logs/evicts

import org.springframework.cache.CacheManager;
import org.springframework.cache.Cache;
import org.springframework.stereotype.Component;

@Component
public class CacheEvictionHandler {
    private final CacheManager cacheManager;

    CacheEvictionHandler(CacheManager cm) { cacheManager = cm; }

    /**
     * Called by MessageListenerAdapter for every Pub/Sub message.
     * @param message  the entity ID (e.g., 'P001') or '*' to clear all
     * @param channel  the Redis channel (e.g., 'cache.invalidate.products')
     */
    public void onEvict(String message, String channel) {
        // Extract cache name: 'cache.invalidate.products' → 'products'
        String cacheName = channel.contains(".")
            ? channel.substring(channel.lastIndexOf('.') + 1)
            : channel;

        Cache cache = cacheManager.getCache(cacheName);
        if (cache == null) {
            System.out.printf("[PubSub] Unknown cache '%s' for channel '%s'%n",
                cacheName, channel);
            return;
        }

        if ("*".equals(message)) {
            cache.clear();
            System.out.printf("[PubSub] Cleared ALL entries from '%s' cache%n", cacheName);
        } else {
            cache.evict(message);
            System.out.printf("[PubSub] Evicted '%s' from '%s' cache%n", message, cacheName);
        }
    }
}

