import org.springframework.cache.CacheManager;
import org.springframework.cache.Cache;
import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;

@Service
public class CacheInvalidationService {
    private static final String CHANNEL_PREFIX = "cache.invalidate.";

    private final CacheManager cacheManager;
    private final RedisTemplate<String, String> redis;

    CacheInvalidationService(CacheManager cm, RedisTemplate<String,String> r) {
        cacheManager=cm; redis=r;
    }

    public void invalidate(String cacheName, String key) {
        // Step 1: Evict from LOCAL L1 cache first:
        Cache cache = cacheManager.getCache(cacheName);
        if (cache != null) cache.evict(key);

        // Step 2: Broadcast to ALL other instances:
        String channel = CHANNEL_PREFIX + cacheName;
        redis.convertAndSend(channel, key);
        // Other instances: receive message → evict from their L1

        System.out.printf("[Invalidated] %s::%s (local+broadcast)%n", cacheName, key);
    }

    public void invalidateAll(String cacheName) {
        // Clear local:
        Cache cache = cacheManager.getCache(cacheName);
        if (cache != null) cache.clear();

        // Broadcast clear-all signal ('*' = clear all):
        redis.convertAndSend(CHANNEL_PREFIX + cacheName, "*");
        System.out.printf("[Invalidated ALL] %s (local+broadcast)%n", cacheName);
    }

    // WHY LOCAL FIRST?
    // If we publish first, there's a tiny window where:
    //   - Other instances evict their L1 (good)
    //   - THIS instance still has stale L1 (bad)
    //   - A request on THIS instance serves stale data from L1
    // Local evict first: this instance is immediately consistent.
    // Publish after: other instances follow within milliseconds.
}

import org.springframework.context.annotation.*;
import org.springframework.data.redis.connection.RedisConnectionFactory;
import org.springframework.data.redis.listener.*;

@Configuration
public class FlipkartPubSubConfig {

    // PatternTopic: one subscription, 3 channels handled by routing in handler
    @Bean
    public RedisMessageListenerContainer flipkartContainer(
            RedisConnectionFactory factory,
            MessageListenerAdapter flipkartAdapter) {
        var container = new RedisMessageListenerContainer();
        container.setConnectionFactory(factory);

        // Single pattern subscription covers all 3 channels:
        // cache.invalidate.products
        // cache.invalidate.categories  
        // cache.invalidate.sellers
        container.addMessageListener(
            flipkartAdapter,
            new PatternTopic("cache.invalidate.*")
        );

        return container;
    }

    @Bean
    public MessageListenerAdapter flipkartAdapter(CacheEvictionHandler handler) {
        // Handler receives both message AND channel name:
        // Spring will call: handler.onEvict(message, channel)
        MessageListenerAdapter adapter = new MessageListenerAdapter(handler, "onEvict");
        return adapter;
    }

    // Alternative: separate subscriptions per channel:
    // container.addMessageListener(productsAdapter, new ChannelTopic("cache.invalidate.products"));
    // container.addMessageListener(categoriesAdapter, new ChannelTopic("cache.invalidate.categories"));
    // Disadvantage: more beans, same logic — PatternTopic is cleaner
}

