import java.util.concurrent.*;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@SpringBootTest
class PubSubIntegrationTest {
    @Autowired CacheManager cacheManager;
    @Autowired RedisTemplate<String, String> redis;
    @Autowired CacheInvalidationService invalidationService;

    @BeforeEach void setup() {
        // Seed the cache:
        cacheManager.getCache("products").put("P001", "Wireless Mouse ₹799");
    }

    @Test
    void publishInvalidation_evictsFromCache() throws Exception {
        // Verify it's in cache:
        assertNotNull(cacheManager.getCache("products").get("P001"),
            "P001 should be in cache before test");

        // Publish invalidation:
        invalidationService.invalidate("products", "P001");

        // Async delivery — wait briefly:
        // The local evict happens synchronously in invalidate().
        // The Pub/Sub message is async — other instances need a moment.
        // For THIS test (same instance): local evict already happened.
        Thread.sleep(50);  // allow async pub/sub processing

        // Assert evicted:
        assertNull(cacheManager.getCache("products").get("P001"),
            "P001 should be evicted from cache after invalidation");
    }

    @Test
    void invalidateAll_clearsEntireCache() throws Exception {
        cacheManager.getCache("products").put("P002", "Keyboard ₹1999");

        invalidationService.invalidateAll("products");
        Thread.sleep(50);

        assertNull(cacheManager.getCache("products").get("P001"));
        assertNull(cacheManager.getCache("products").get("P002"));
    }
}

