import org.springframework.cache.annotation.*;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class FlipkartProductService {
    private final ProductRepository repo;
    private final CacheInvalidationService invalidation;

    FlipkartProductService(ProductRepository r, CacheInvalidationService i) {
        repo=r; invalidation=i;
    }

    // @Cacheable: standard Spring cache for reads
    @Cacheable(value="products", key="#id")
    public Product findById(String id) {
        System.out.println("[DB] Loading product " + id);
        return repo.findById(id).orElseThrow();
    }

    // Update: save to DB + broadcast invalidation to all instances
    @Transactional
    public Product updateProduct(Product product) {
        Product saved = repo.save(product);
        // Evict local + broadcast to other 9 instances:
        invalidation.invalidate("products", product.getId());
        return saved;
    }

    // Delete: remove from DB + invalidate product + all category lists
    @Transactional
    public void deleteProduct(String id) {
        Product p = repo.findById(id).orElseThrow();
        repo.deleteById(id);
        invalidation.invalidate("products", id);
        // Category lists that contained this product are now stale:
        invalidation.invalidateAll("categories");
    }

    // Create: new product may appear in category lists
    @Transactional
    public Product createProduct(Product product) {
        Product saved = repo.save(product);
        // Category lists may now be missing this new product:
        invalidation.invalidateAll("categories");
        return saved;
    }

    // @Cacheable + manual invalidation coexistence:
    // @Cacheable handles the READ path (automatic cache-aside)
    // Manual invalidation handles the WRITE path (pub/sub broadcast)
    // Together: reads are fast (cached), writes propagate immediately

    interface ProductRepository {
        java.util.Optional<Product> findById(String id);
        Product save(Product p);
        void deleteById(String id);
    }
    record Product(String id, String name, double price) {}
}

