import org.springframework.cache.*;
import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.data.redis.listener.*;
import org.springframework.stereotype.*;
import org.springframework.context.annotation.*;

@Service
class RestaurantStatusBroadcaster {
    private final RedisTemplate<String,String> redis;
    private final CacheManager cacheManager;
    private final RestaurantRepository repo;

    RestaurantStatusBroadcaster(RedisTemplate<String,String> r, CacheManager cm, RestaurantRepository rr){
        redis=r; cacheManager=cm; repo=rr;
    }

    public void setOpen(String restaurantId) {
        repo.updateStatus(restaurantId, "OPEN");
        evictAndBroadcast(restaurantId, "OPEN");
    }

    public void setClosed(String restaurantId) {
        repo.updateStatus(restaurantId, "CLOSED");
        evictAndBroadcast(restaurantId, "CLOSED");
    }

    private void evictAndBroadcast(String id, String newStatus) {
        // Local evict first:
        Cache c = cacheManager.getCache("restaurantStatus");
        if (c != null) c.evict(id);
        // Broadcast to all instances:
        redis.convertAndSend("restaurant.status." + id, newStatus);
        System.out.printf("[RestaurantStatus] %s → %s (broadcast)%n", id, newStatus);
    }

    interface RestaurantRepository { void updateStatus(String id, String status); }
}

@Component
class RestaurantStatusHandler {
    private final CacheManager cm;
    RestaurantStatusHandler(CacheManager c){cm=c;}
    public void onStatus(String message, String channel){
        // channel: 'restaurant.status.R001' → extract ID
        String restaurantId=channel.substring(channel.lastIndexOf('.')+1);
        Cache c=cm.getCache("restaurantStatus");
        if(c!=null){c.evict(restaurantId);
            System.out.printf("[Handler] Evicted restaurantStatus::%s%n",restaurantId);}
    }
}

@Configuration
class RestaurantStatusConfig {
    @Bean RedisMessageListenerContainer rsContainer(
            RedisConnectionFactory f, MessageListenerAdapter rsAdapter){
        var c=new RedisMessageListenerContainer();
        c.setConnectionFactory(f);
        c.addMessageListener(rsAdapter,new PatternTopic("restaurant.status.*"));
        return c;
    }
    @Bean MessageListenerAdapter rsAdapter(RestaurantStatusHandler h){
        return new MessageListenerAdapter(h,"onStatus");
    }
}

// WHY 30-SECOND TTL IS NOT ACCEPTABLE:
// A restaurant closes due to a kitchen fire.
// 30 seconds × (orders/second) = many orders accepted for a closed restaurant!
// Swiggy SLA: restaurant status must propagate within 5 seconds.
// Pub/Sub delivers in <1ms → vastly better than any TTL.

