import org.springframework.cache.*;
import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.*;

@Service
public class SessionInvalidationService {
    private static final String CHANNEL = "session.invalidate";
    private static final String CACHE   = "sessions";

    private final CacheManager cacheManager;
    private final RedisTemplate<String,String> redis;

    SessionInvalidationService(CacheManager cm, RedisTemplate<String,String> r){
        cacheManager=cm; redis=r;
    }

    // Put session in local L1 cache:
    public void cacheSession(String userId, Object sessionData){
        Cache sessions = cacheManager.getCache(CACHE);
        if(sessions!=null) sessions.put(userId, sessionData);
    }

    // Get session from L1 cache:
    public Object getSession(String userId){
        Cache sessions = cacheManager.getCache(CACHE);
        Cache.ValueWrapper v = sessions!=null ? sessions.get(userId) : null;
        return v!=null ? v.get() : null;
    }

    // Logout: invalidate locally + broadcast to all instances:
    public void logout(String userId){
        // Local eviction:
        Cache sessions = cacheManager.getCache(CACHE);
        if(sessions!=null) sessions.evict(userId);

        // Broadcast — all other instances will also evict:
        redis.convertAndSend(CHANNEL, userId);
        System.out.printf("[Logout] User %s: session evicted + broadcast%n", userId);
    }
}

// Handler on all instances:
@Component
class SessionEvictionHandler {
    private final CacheManager cacheManager;
    SessionEvictionHandler(CacheManager cm){cacheManager=cm;}

    public void onSessionInvalidate(String userId){
        Cache sessions = cacheManager.getCache("sessions");
        if(sessions!=null){
            sessions.evict(userId);
            System.out.printf("[SessionHandler] Evicted session for %s%n", userId);
        }
    }
}

