@Component
class CacheInvalidationRouter implements MessageListener {
    private final CacheManager cm;
    CacheInvalidationRouter(CacheManager c){cm=c;}

    @Override
    public void onMessage(org.springframework.data.redis.connection.Message msg, byte[] pattern){
        String channel=new String(msg.getChannel());
        String body   =new String(msg.getBody());

        // Route by channel: 'cache.products.invalidate' → 'products' cache
        String[] parts=channel.split("\\.");
        if(parts.length<2) return;
        String cacheName=parts[1];  // 'products', 'categories', 'merchants'

        Cache cache=cm.getCache(cacheName);
        if(cache==null){
            System.out.println("[Router] No cache named: "+cacheName); return;
        }
        if("*".equals(body)){
            cache.clear();
            System.out.printf("[Router] CLEAR ALL %s cache%n",cacheName);
        }else{
            cache.evict(body);
            System.out.printf("[Router] EVICT %s from %s cache%n",body,cacheName);
        }
    }
}

@Configuration
class RouterConfig {
    @Bean RedisMessageListenerContainer routerContainer(
            org.springframework.data.redis.connection.RedisConnectionFactory f,
            CacheInvalidationRouter router){
        var c=new RedisMessageListenerContainer();
        c.setConnectionFactory(f);
        c.addMessageListener(router,new PatternTopic("cache.*"));
        return c;
    }
}

