import org.springframework.cache.CacheManager;
import org.springframework.context.event.EventListener;
import org.springframework.stereotype.Component;
import org.springframework.data.redis.connection.*;
import java.time.LocalDateTime;

@Component
public class RedisReconnectListener {
    private final CacheManager cacheManager;

    RedisReconnectListener(CacheManager cm) { cacheManager = cm; }

    // Spring Data Redis publishes RedisConnectionFailedEvent and
    // can be listened to for connection lifecycle events.
    // In Lettuce (default client), we can use after-reconnect callback:

    @EventListener(org.springframework.data.redis.connection.RedisConnectionFailedEvent.class)
    public void onConnectionFailed(Object event) {
        System.out.printf("[Redis] Connection LOST at %s — L1 cache may become stale!%n",
            LocalDateTime.now());
    }

    // On reconnect: conservatively clear all L1 caches
    // (Any messages published during the disconnection window were missed)
    public void onReconnect() {
        System.out.printf("[Redis] Connection RESTORED at %s%n", LocalDateTime.now());
        int cleared = 0;
        for (String cacheName : cacheManager.getCacheNames()) {
            cacheManager.getCache(cacheName).clear();
            cleared++;
            System.out.printf("[Redis] Cleared L1 cache: '%s'%n", cacheName);
        }
        System.out.printf("[Redis] Cleared %d L1 caches after reconnect.%n", cleared);
    }

    // WHY CLEAR ON RECONNECT?
    // During disconnection (say, 2 seconds):
    //   Many products may have been updated on other instances
    //   Their Pub/Sub invalidation events were published but not received
    //   THIS instance missed all of them
    //   L1 cache has stale data for items changed in those 2 seconds
    // Safest approach: clear L1 on reconnect
    //   Next requests all miss L1 → fetch fresh from Redis L2 or DB
    //   Slight latency spike: fresh loads take 0.3ms instead of 0.01ms
    //   Worth it: no stale data served

    public static void main(String[] a) {
        System.out.println("On reconnect: clear L1 → all instances consistent again");
    }
}

