        String k="rate:fk:"+uid+":"+(System.currentTimeMillis()/60_000);
        Long c=redis.opsForValue().increment(k);
        if(c==1) redis.expire(k,Duration.ofMinutes(2));
        return c<=limit;
    }
}

@Service
class FKCatalogSyncJob {
    public final AtomicInteger syncCount=new AtomicInteger(0);
    private final RedisTemplate<String,String> redis;
    FKCatalogSyncJob(RedisTemplate<String,String> r){redis=r;}
    public boolean sync(String jobId){
        String k="lock:catalog:sync:"+jobId;
        Boolean ok=redis.opsForValue().setIfAbsent(k,"1",Duration.ofMinutes(10));
        if(!Boolean.TRUE.equals(ok)) return false;
        try{
            syncCount.incrementAndGet();
            redis.convertAndSend("cache.invalidate.products","*");
            return true;
        }finally{redis.delete(k);}
    }
}

